  "08-comparison-workbench.html": shell({
    artifact: "comparison-workbench",
    title: "Client State — Approach Comparison",
    eyebrow: "Comparison workbench",
    summary: "For this app's scope, a query-cache layer beats both hand-rolled context and a full store: less code, ordered writes, and built-in retries.",
    body: `<section class="section panel" data-primitive="meta-strip" data-variant="inline"><div class="meta"><div data-slot="item"><span class="label" data-slot="key">Decision</span> <b data-slot="value">client state layer</b></div><div data-slot="item"><span class="label" data-slot="key">Options</span> <b data-slot="value">3</b></div></div></section>
<section class="section"><h2>Options</h2><div data-primitive="comparison-grid" data-variant="cards"><article data-slot="option"><div data-slot="option-title">Hand-rolled context</div><div data-slot="option-body">Minimal deps, but manual cache, retries, and invalidation.</div></article><article data-slot="option" data-state="recommended"><div data-slot="option-title">Query-cache layer <span class="pill" data-slot="recommended" data-state="selected">recommended</span></div><div data-slot="option-body">Caching, retries, and invalidation handled; small surface to learn.</div></article><article data-slot="option"><div data-slot="option-title">Full client store</div><div data-slot="option-body">Powerful, but heavier and overkill for this data shape.</div></article></div></section>
<section class="section"><h2>Tradeoffs</h2><div data-primitive="risk-table"><div class="table-wrap"><table><thead><tr><th data-slot="head">Axis</th><th data-slot="head">Context</th><th data-slot="head">Query cache</th><th data-slot="head">Store</th></tr></thead><tbody><tr data-slot="row"><td>Boilerplate</td><td><span class="badge" data-state="high">HIGH</span></td><td><span class="badge" data-state="low">LOW</span></td><td><span class="badge" data-state="med">MED</span></td></tr><tr data-slot="row"><td>Retries built in</td><td>no</td><td>yes</td><td>no</td></tr><tr data-slot="row"><td>Learning cost</td><td><span class="badge" data-state="low">LOW</span></td><td><span class="badge" data-state="med">MED</span></td><td><span class="badge" data-state="high">HIGH</span></td></tr></tbody></table></div></div></section>
<section class="section"><aside class="callout" data-primitive="callout" data-variant="success"><span data-slot="body"><b>Use the query-cache layer.</b> It removes the most boilerplate and gives ordered writes and retries for free. Revisit only if the app grows shared cross-screen state.</span></aside></section>`
  }),
